SELECT profile_id
FROM profiles
WHERE time_percentage > (SELECT AVG(time_percentage) FROM profiles);

SELECT COUNT(*) 
FROM routines 
WHERE complexity = 'high';

SELECT DISTINCT u.user_name, u.role
FROM users u
JOIN performance_reports pr ON u.user_id = pr.created_by;

SELECT profiles.profile_id, applications.application_name
FROM profiles
JOIN applications ON profiles.application_id = applications.application_id;

SELECT application_id, routine_id, profile_date
FROM profiles
WHERE profile_id > 5;
